1	/**
2	 * Shared inbound-media pipeline for bot adapters.
3	 *
4	 * Every platform receives media differently — WhatsApp via the Kapso webhook +
5	 * media id, Telegram via `getFile` + `file_id` — but once the raw bytes are in
6	 * hand the decision is identical:
7	 *
8	 *   - video / sticker    → not supported yet, polite reply (no download)
9	 *   - audio / voice note → transcribe (Whisper) → treat transcript as the message
10	 *   - image / document   → upload to GAIA storage → attach via fileIds/fileData
11	 *
12	 * This module owns that decision plus the size caps, filenames, prompts and
13	 * error copy that go with it, so every adapter behaves identically and the
14	 * logic is unit-testable without any platform SDK. Adapters supply only a
15	 * platform-specific {@link IncomingMedia} descriptor and a download thunk.
16	 */
17	import type { GaiaClient } from "../api";
18	import type { BotFileData, BotUserContext } from "../types";
19	
20	const MB = 1024 * 1024;
21	
22	/** Upload/transcribe size caps shared by every platform. */
23	export const BOT_MEDIA_LIMITS = {
24	  /** GAIA upload pipeline cap (the backend rejects anything larger). */
25	  file: 10 * MB,
26	  /** OpenAI Whisper hard cap, matched by the backend transcribe endpoint. */
27	  audio: 25 * MB,
28	} as const;
29	
30	/** Normalised media kind, identical across platforms. */
31	export type MediaKind = "image" | "audio" | "video" | "document" | "sticker";
32	
33	/**
34	 * Platform-agnostic descriptor of an inbound media message. Each adapter maps
35	 * its native payload (Kapso `ExtractedMedia`, Telegram `PhotoSize`/`Voice`/…)
36	 * onto this shape before handing it to {@link processBotMedia}.
37	 */
38	export interface IncomingMedia {
39	  kind: MediaKind;
40	  /** True for push-to-talk voice notes (only meaningful when `kind === "audio"`). */
41	  isVoiceNote: boolean;
42	  /** Best-known mime type; callers fall back to a per-kind default upstream. */
43	  mimeType: string;
44	  /** Original filename for documents; absent for inline media. */
45	  filename?: string;
46	  /** Caption sent alongside the media, used as the prompt when present. */
47	  caption?: string;
48	}
49	
50	/**
51	 * Result of {@link processBotMedia}. The adapter either streams a chat turn
52	 * (optionally with uploaded attachments) or sends a single plain reply.
53	 */
54	export type MediaOutcome =
55	  | { action: "chat"; text: string; attachments: BotFileData[] }
56	  | { action: "reply"; text: string };
57	
58	/** Reply shown for media kinds GAIA does not process yet (video, sticker, …). */
59	export function unsupportedMediaMessage(kind: string): string {
60	  const label =
61	    kind === "video"
62	      ? "videos"
63	      : kind === "sticker"
64	        ? "stickers"
65	        : `${kind} messages`;
66	  return `I can't process ${label} yet — please send your message as text, an image, a document, or a voice note. Type /help for available commands.`;
67	}
68	
69	/** Maps an upload/transcribe failure to a user-facing reply. */
70	export function friendlyMediaError(kind: MediaKind, err: unknown): string {
71	  const status = (err as { status?: number })?.status;
72	  const responseStatus = (err as { response?: { status?: number } })?.response
73	    ?.status;
74	  const code = status ?? responseStatus;
75	
76	  if (code === 401 || code === 403) {
77	    return "I need you to link your GAIA account first before I can read attachments. Send /auth to get started.";
78	  }
79	  if (code === 413) {
80	    return `That ${kind} is too large for me to process. Please share a smaller file.`;
81	  }
82	  if (code === 415) {
83	    return `I can't read this kind of ${kind} yet. Try a common format like JPG, PNG, PDF, or an OGG voice note.`;
84	  }
85	  if (code === 429) {
86	    return "You've reached your file upload limit for now. Please try again later, or upgrade your plan for higher limits.";
87	  }
88	  return "Something went wrong while processing your attachment. Please try again in a moment.";
89	}
90	
91	/** Returns a leading-dot file extension for a known mime type, or `fallback`. */
92	export function extensionForMime(mimeType: string, fallback: string): string {
93	  const mime = mimeType.split(";")[0].trim().toLowerCase();
94	  const lookup: Record<string, string> = {
95	    "image/jpeg": ".jpg",
96	    "image/png": ".png",
97	    "image/gif": ".gif",
98	    "image/webp": ".webp",
99	    "image/bmp": ".bmp",
100	    "audio/ogg": ".ogg",
101	    "audio/opus": ".opus",
102	    "audio/mpeg": ".mp3",
103	    "audio/mp3": ".mp3",
104	    "audio/mp4": ".m4a",
105	    "audio/m4a": ".m4a",
106	    "audio/wav": ".wav",
107	    "audio/webm": ".webm",
108	    "audio/aac": ".aac",
109	    "application/pdf": ".pdf",
110	    "application/msword": ".doc",
