114	      ".xlsx",
115	    "application/vnd.openxmlformats-officedocument.presentationml.presentation":
116	      ".pptx",
117	    "text/plain": ".txt",
118	    "text/markdown": ".md",
119	    "text/csv": ".csv",
120	    "application/json": ".json",
121	  };
