123	}
124	
125	/**
126	 * Turns an inbound media message into the next action for the adapter:
127	 * transcribe audio into a chat turn, upload an image/document and attach it,
128	 * reject an unsupported kind, or reject an oversize payload.
129	 *
130	 * `downloadBytes` is a thunk so unsupported kinds (video, sticker) never incur
131	 * a download. The only side effects are the GAIA upload/transcribe network
132	 * calls, injected via {@link GaiaClient}; everything else is pure, which keeps
133	 * the routing logic testable with a fake client and no platform SDK.
134	 */
135	export async function processBotMedia(
136	  gaia: GaiaClient,
137	  media: IncomingMedia,
138	  downloadBytes: () => Promise<Uint8Array>,
139	  ctx: BotUserContext,
140	): Promise<MediaOutcome> {
141	  if (media.kind === "video" || media.kind === "sticker") {
142	    return { action: "reply", text: unsupportedMediaMessage(media.kind) };
143	  }
144	
145	  const bytes = await downloadBytes();
146	
147	  if (media.kind === "audio") {
148	    if (bytes.byteLength > BOT_MEDIA_LIMITS.audio) {
149	      return {
150	        action: "reply",
151	        text: `That voice note is too large to transcribe (limit: ${
152	          BOT_MEDIA_LIMITS.audio / MB
153	        } MB). Please send a shorter message.`,
154	      };
155	    }
156	
157	    const filename = media.isVoiceNote
158	      ? "voice-note.ogg"
159	      : `audio${extensionForMime(media.mimeType, ".ogg")}`;
160	    const transcript = (
161	      await gaia.transcribeAudio(
162	        { data: Buffer.from(bytes), filename, mimeType: media.mimeType },
163	        ctx,
164	      )
165	    ).trim();
166	
167	    if (!transcript) {
168	      return {
169	        action: "reply",
170	        text: "I couldn't understand that audio. Could you try recording again or sending a text message?",
171	      };
172	    }
173	
174	    // Caption (if any) precedes the transcript so the agent sees both signals.
175	    const text = media.caption
176	      ? `${media.caption.trim()}\n\n${transcript}`
177	      : transcript;
178	    return { action: "chat", text, attachments: [] };
179	  }
180	
181	  // image | document
182	  if (bytes.byteLength > BOT_MEDIA_LIMITS.file) {
183	    return {
184	      action: "reply",
185	      text: `That file is too large to process (limit: ${
186	        BOT_MEDIA_LIMITS.file / MB
187	      } MB). Please share a smaller file.`,
188	    };
189	  }
190	
191	  const filename =
192	    media.filename ??
193	    (media.kind === "image"
194	      ? `image${extensionForMime(media.mimeType, ".jpg")}`
195	      : `document${extensionForMime(media.mimeType, "")}`);
196	  const fileData = await gaia.uploadFile(
197	    { data: Buffer.from(bytes), filename, mimeType: media.mimeType },
198	    ctx,
199	  );
200	
201	  // Caption is the user's prompt when present; otherwise ask the agent to
202	  // describe (image) or review (document) the attachment.
203	  const attachmentNoun = media.filename ? "document" : "file";
204	  const fallbackPrompt =
205	    media.kind === "image"
206	      ? "Please describe this image."
207	      : `Please review this ${attachmentNoun} and tell me what's in it.`;
208	  const text = media.caption?.trim() || fallbackPrompt;
209	  return { action: "chat", text, attachments: [fileData] };
210	}
